/**
 * Generated by `createservice subscription.ActivateSubscriptionContextService --type mutations`
 */

const { GQLError, GQLErrorCode: { BAD_USER_INPUT } } = require('@open-condo/keystone/errors')
const { GQLCustomSchema, find, getById } = require('@open-condo/keystone/schema')

const { INVOICE_STATUS_PAID } = require('@condo/domains/marketplace/constants')
const access = require('@condo/domains/subscription/access/ActivateSubscriptionContextService')
const { SUBSCRIPTION_CONTEXT_STATUS } = require('@condo/domains/subscription/constants')
const { SubscriptionContext } = require('@condo/domains/subscription/utils/serverSchema')

/**
 * List of possible errors, that this custom schema can throw
 * They will be rendered in documentation section in GraphiQL for this custom schema
 */
const ERRORS = {
    SUBSCRIPTION_CONTEXT_NOT_FOUND: {
        mutation: 'activateSubscriptionContext',
        variable: ['data', 'subscriptionContext'],
        code: BAD_USER_INPUT,
        type: 'SUBSCRIPTION_CONTEXT_NOT_FOUND',
        message: 'SubscriptionContext not found',
    },
    SUBSCRIPTION_CONTEXT_INVALID_STATUS: {
        mutation: 'activateSubscriptionContext',
        variable: ['data', 'subscriptionContext'],
        code: BAD_USER_INPUT,
        type: 'SUBSCRIPTION_CONTEXT_INVALID_STATUS',
        message: 'SubscriptionContext must have status CREATED',
    },
    INVOICE_NOT_FOUND: {
        mutation: 'activateSubscriptionContext',
        variable: ['data', 'subscriptionContext'],
        code: BAD_USER_INPUT,
        type: 'INVOICE_NOT_FOUND',
        message: 'Invoice not found for SubscriptionContext',
    },
    INVOICE_NOT_PAID: {
        mutation: 'activateSubscriptionContext',
        variable: ['data', 'subscriptionContext'],
        code: BAD_USER_INPUT,
        type: 'INVOICE_NOT_PAID',
        message: 'Invoice is not paid',
    },
    MULTI_PAYMENT_NOT_FOUND: {
        mutation: 'activateSubscriptionContext',
        variable: ['data', 'subscriptionContext'],
        code: BAD_USER_INPUT,
        type: 'MULTI_PAYMENT_NOT_FOUND',
        message: 'MultiPayment not found for invoice',
    },
    PAYMENT_NOT_FOUND: {
        mutation: 'activateSubscriptionContext',
        variable: ['data', 'subscriptionContext'],
        code: BAD_USER_INPUT,
        type: 'PAYMENT_NOT_FOUND',
        message: 'Payment not found in MultiPayment',
    },
}

const ActivateSubscriptionContextService = new GQLCustomSchema('ActivateSubscriptionContextService', {
    types: [
        {
            access: true,
            type: 'input ActivateSubscriptionContextInput { dv: Int!, sender: SenderFieldInput!, subscriptionContext: SubscriptionContextWhereUniqueInput! }',
        },
        {
            access: true,
            type: 'type ActivateSubscriptionContextOutput { subscriptionContext: SubscriptionContext }',
        },
    ],

    mutations: [
        {
            access: access.canActivateSubscriptionContext,
            schema: 'activateSubscriptionContext(data: ActivateSubscriptionContextInput!): ActivateSubscriptionContextOutput',
            doc: {
                summary: 'Activates a subscription context with status CREATED. Checks that invoice is paid, retrieves payment method from multiPayment, and updates context status to DONE.',
                errors: ERRORS,
            },
            resolver: async (parent, args, context) => {
                const { data } = args
                const { dv, sender, subscriptionContext: subscriptionContextInput } = data

                const [subscriptionContext] = await find('SubscriptionContext', {
                    id: subscriptionContextInput.id,
                    deletedAt: null,
                })
                if (!subscriptionContext) {
                    throw new GQLError(ERRORS.SUBSCRIPTION_CONTEXT_NOT_FOUND, context)
                }

                if (subscriptionContext.status !== SUBSCRIPTION_CONTEXT_STATUS.CREATED) {
                    throw new GQLError(ERRORS.SUBSCRIPTION_CONTEXT_INVALID_STATUS, context)
                }

                if (!subscriptionContext.invoice) {
                    throw new GQLError(ERRORS.INVOICE_NOT_FOUND, context)
                }
                const invoice = await getById('Invoice', subscriptionContext.invoice)
                if (!invoice) {
                    throw new GQLError(ERRORS.INVOICE_NOT_FOUND, context)
                }
                if (invoice.status !== INVOICE_STATUS_PAID) {
                    throw new GQLError(ERRORS.INVOICE_NOT_PAID, context)
                }

                const [payment] = await find('Payment', {
                    invoice: { id: invoice.id },
                    deletedAt: null,
                })
                if (!payment) {
                    throw new GQLError(ERRORS.MULTI_PAYMENT_NOT_FOUND, context)
                }

                const [multiPayment] = await find('MultiPayment', {
                    id: payment.multiPayment,
                    deletedAt: null,
                })
                if (!multiPayment) {
                    throw new GQLError(ERRORS.MULTI_PAYMENT_NOT_FOUND, context)
                }

                const paymentMethod = multiPayment.meta?.paymentMethod || null

                const frozenPaymentInfo = {
                    paymentMethod,
                    invoice: {
                        id: invoice.id,
                        rows: invoice.rows,
                        toPay: invoice.toPay,
                    },
                    pricingRuleId: subscriptionContext.subscriptionPlanPricingRule,
                }

                await SubscriptionContext.update(context, subscriptionContext.id, {
                    dv,
                    sender,
                    status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                    bindingId: paymentMethod?.bindingId || null,
                    frozenPaymentInfo,
                })

                const updatedSubscriptionContext = await getById('SubscriptionContext', subscriptionContext.id)
                return { subscriptionContext: updatedSubscriptionContext }
            },
        },
    ],
})

module.exports = {
    ActivateSubscriptionContextService,
    ERRORS,
}
